using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private ServiceRegistry _registry = null!;

    [TestInitialize]
    public void Setup() => _registry = new ServiceRegistry();

    [TestMethod]
    public void Register_And_Resolve_ReturnsSameInstance()
    {
        var service = new FakeService();
        _registry.Register<IFakeService>(service);

        var resolved = _registry.Resolve<IFakeService>();

        Assert.AreSame(service, resolved);
    }

    [TestMethod]
    public void Resolve_Unregistered_ReturnsNull()
    {
        var result = _registry.Resolve<IFakeService>();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void ResolveRequired_Unregistered_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _registry.ResolveRequired<IFakeService>());
    }

    [TestMethod]
    public void Register_Null_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _registry.Register<IFakeService>(null!));
    }

    [TestMethod]
    public void Register_OverwritesPreviousRegistration()
    {
        var first = new FakeService();
        var second = new FakeService();

        _registry.Register<IFakeService>(first);
        _registry.Register<IFakeService>(second);

        Assert.AreSame(second, _registry.Resolve<IFakeService>());
    }

    [TestMethod]
    public void Clear_RemovesAllServices()
    {
        _registry.Register<IFakeService>(new FakeService());
        _registry.Register<IAnotherService>(new AnotherService());

        _registry.Clear();

        Assert.IsNull(_registry.Resolve<IFakeService>());
        Assert.IsNull(_registry.Resolve<IAnotherService>());
        Assert.AreEqual(0, _registry.GetAll().Count);
    }

    [TestMethod]
    public void Remove_UnregistersService()
    {
        _registry.Register<IFakeService>(new FakeService());

        _registry.Remove<IFakeService>();

        Assert.IsNull(_registry.Resolve<IFakeService>());
    }

    [TestMethod]
    public void Remove_LeavesOtherServicesIntact()
    {
        var other = new AnotherService();
        _registry.Register<IFakeService>(new FakeService());
        _registry.Register<IAnotherService>(other);

        _registry.Remove<IFakeService>();

        Assert.IsNotNull(_registry.Resolve<IAnotherService>());
        Assert.AreSame(other, _registry.Resolve<IAnotherService>());
    }

    [TestMethod]
    public void GetAll_ReturnsAllRegisteredServices()
    {
        var fake = new FakeService();
        var another = new AnotherService();
        _registry.Register<IFakeService>(fake);
        _registry.Register<IAnotherService>(another);

        var all = _registry.GetAll();

        Assert.AreEqual(2, all.Count);
        Assert.IsTrue(all.Contains(fake));
        Assert.IsTrue(all.Contains(another));
    }

    // Test helpers
    private interface IFakeService;
    private interface IAnotherService;
    private sealed class FakeService : IFakeService;
    private sealed class AnotherService : IAnotherService;
}

